- Use Angular CLI to generate tests (`ng generate component <component-name> --spec`)
- Install Vitest and JSDOM for testing (`npm install vitest jsdom --save-dev`)
- Configure `angular.json` with Vitest as the test runner:
  ```json
  "test": {
    "builder": "@angular-devkit/build-angular:karma",
    "options": {
      "polyfills": [
        "zone.js"
      ],
      "main": "src/test.ts",
      "tsConfig": "src/tsconfig.spec.json",
      "karmaConfig": "src/karma.conf.js",
      "assets": [
        "src/favicon.ico",
        "src/assets"
      ],
      "styles": [
        "src/styles.css"
      ],
      "scripts": []
    },
    "configurations": {
      "production": {
        "fileReplacements": [
          {
            "replace": "src/environments/environment.ts",
            "with": "src/environments/environment.prod.ts"
          }
        ]
      }
    }
  }
  ```
- Use Jest for mocking services:
  ```typescript
  import { TestBed } from '@angular/core/testing';
  import { HttpClientTestingModule, HttpTestingController } from '@angular/common/http/testing';
  import { MyService } from './my.service';

  describe('MyService', () => {
    let service: MyService;
    let httpMock: HttpTestingController;

    beforeEach(() => {
      TestBed.configureTestingModule({
        imports: [HttpClientTestingModule],
        providers: [MyService]
      });
      service = TestBed.inject(MyService);
      httpMock = TestBed.inject(HttpTestingController);
    });

    afterEach(() => {
      httpMock.verify();
    });

    it('should be created', () => {
      expect(service).toBeTruthy();
    });

    it('should fetch data from the server', () => {
      const mockData = { key: 'value' };
      service.getData().subscribe(data => {
        expect(data).toEqual(mockData);
      });
      const req = httpMock.expectOne('https://api.example.com/data');
      expect(req.request.method).toBe('GET');
      req.flush(mockData);
    });
  });
  ```
- Use `ng test` to run tests with Vitest.
